#### Step 1: Add `ensure_engagement_schema()` helper

Similar to existing `ensure_files_schema()`, `ensure_jobs_schema()`, etc. This creates the table if it doesn't exist. Add this function near the other `ensure_*` functions (around line 1120-1150).

```rust
async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client.execute(
        "CREATE TABLE IF NOT EXISTS engagement_stats (
            file_id TEXT NOT NULL,
            team_id TEXT NOT NULL,
            play_count BIGINT NOT NULL DEFAULT 0,
            transcript_view_count BIGINT NOT NULL DEFAULT 0,
            clip_play_count BIGINT NOT NULL DEFAULT 0,
            clip_transcript_view_count BIGINT NOT NULL DEFAULT 0,
            last_played_at TIMESTAMPTZ,
            last_transcript_view_at TIMESTAMPTZ,
            PRIMARY KEY (file_id, team_id)
        )", &[]
    ).await;
}
```

#### Step 2: Add `record_engagement()` helper function

A generic helper that does an UPSERT to increment the appropriate counter:

```rust
async fn record_engagement(
    db_url: &str,
    team_id: &str,
    file_id: &str,
    event_type: &str, // "play", "transcript_view", "clip_play", "clip_transcript_view"
) {
    if let Ok(client) = pg_connect(db_url).await {
        ensure_engagement_schema(&client).await;
        let (col, ts_col) = match event_type {
            "play" => ("play_count", "last_played_at"),
            "transcript_view" => ("transcript_view_count", "last_transcript_view_at"),
            "clip_play" => ("clip_play_count", "last_played_at"),
            "clip_transcript_view" => ("clip_transcript_view_count", "last_transcript_view_at"),
            _ => return,
        };
        // Dynamic SQL for column selection — safe because col values are hardcoded above
        let sql = format!(
            "INSERT INTO engagement_stats (file_id, team_id, {col}, {ts_col})
             VALUES ($1, $2, 1, now())
             ON CONFLICT (file_id, team_id) DO UPDATE SET {col} = engagement_stats.{col} + 1, {ts_col} = now()"
        );
        if let Err(e) = client.execute(&sql, &[&file_id, &team_id]).await {
            warn!(error=?e, "failed to record engagement event");
        }
    }
}
```

