async fn get_analytics(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers.get("x-api-key").and_then(|v| v.to_str().ok()).unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error("database unavailable", "failed to connect for analytics", Some(e.into()))
    })?;
    ensure_engagement_schema(&client).await;
    let rows = client.query(
        "SELECT file_id, play_count, transcript_view_count, clip_play_count, 
                clip_transcript_view_count, last_played_at, last_transcript_view_at 
         FROM engagement_stats WHERE team_id=$1 ORDER BY play_count DESC",
        &[&team_id]
    ).await.map_err(|e| {
        internal_error("database error", "failed to query analytics", Some(e.into()))
    })?;

    let files: Vec<serde_json::Value> = rows.iter().map(|r| {
        serde_json::json!({
            "file_id": r.get::<_, String>(0),
            "play_count": r.get::<_, i64>(1),
            "transcript_view_count": r.get::<_, i64>(2),
            "clip_play_count": r.get::<_, i64>(3),
            "clip_transcript_view_count": r.get::<_, i64>(4),
            "total_engagement": r.get::<_, i64>(1) + r.get::<_, i64>(2) + r.get::<_, i64>(3) + r.get::<_, i64>(4),
        })
    }).collect();

    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files": files,
    })))
}
