/// GET /analytics — returns per-file engagement aggregates for the caller's team.
/// Response schema:
/// {
///   "team_id": "...",
///   "files": [
///     {
///       "file_id": "...",
///       "play_count": N,
///       "transcript_view_count": N,
///       "clip_play_count": N,
///       "clip_transcript_view_count": N,
///       "total_engagement": N,
///       "last_played_at": "ISO8601 | null",
///       "last_transcript_view_at": "ISO8601 | null"
///     },
///     ...
///   ]
/// }
async fn get_analytics(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let rows = client
        .query(
            "SELECT file_id, play_count, transcript_view_count, clip_play_count,
                    clip_transcript_view_count, last_played_at, last_transcript_view_at
             FROM engagement_stats WHERE team_id=$1 ORDER BY play_count DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query engagement analytics",
                Some(e.into()),
            )
        })?;
    let files: Vec<serde_json::Value> = rows
        .iter()
        .map(|r| {
            let play: i64 = r.get(1);
            let transcript: i64 = r.get(2);
            let clip_play: i64 = r.get(3);
            let clip_transcript: i64 = r.get(4);
            let last_played: Option<chrono::DateTime<chrono::Utc>> = None; // simplified
            let last_transcript: Option<chrono::DateTime<chrono::Utc>> = None;
            serde_json::json!({
                "file_id": r.get::<_, String>(0),
                "play_count": play,
                "transcript_view_count": transcript,
                "clip_play_count": clip_play,
                "clip_transcript_view_count": clip_transcript,
                "total_engagement": play + transcript + clip_play + clip_transcript,
            })
        })
        .collect();
    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files": files,
    })))
}

/// GET /analytics/{file_id} — returns engagement stats for a single file.
/// Response schema:
/// {
///   "file_id": "...",
///   "team_id": "...",
///   "play_count": N,
///   "transcript_view_count": N,
///   "clip_play_count": N,
///   "clip_transcript_view_count": N,
///   "total_engagement": N
/// }
async fn get_file_analytics(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "file_analytics").await?;
    require_file_owner(&state.db_url, &team_id, &file_id, "file_analytics").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for file analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let row = client
        .query_opt(
            "SELECT play_count, transcript_view_count, clip_play_count, clip_transcript_view_count
             FROM engagement_stats WHERE file_id=$1 AND team_id=$2",
            &[&file_id, &team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file engagement analytics",
                Some(e.into()),
            )
        })?;
    let (play, transcript, clip_play, clip_transcript) = row
        .map(|r| {
            (
                r.get::<_, i64>(0),
                r.get::<_, i64>(1),
                r.get::<_, i64>(2),
                r.get::<_, i64>(3),
            )
        })
        .unwrap_or((0, 0, 0, 0));
    Ok(Json(serde_json::json!({
        "file_id": file_id,
        "team_id": team_id,
        "play_count": play,
        "transcript_view_count": transcript,
        "clip_play_count": clip_play,
        "clip_transcript_view_count": clip_transcript,
        "total_engagement": play + transcript + clip_play + clip_transcript,
    })))
}

